class Solution:
    def shiftDistance(self, s: str, t: str, nextCost: List[int], previousCost: List[int]) -> int:
        INF = 10**30
        n = 26
        dist = [[INF]*n for _ in range(n)]
        for i in range(n):
            dist[i][i] = 0
            dist[i][(i+1)%n] = min(dist[i][(i+1)%n], nextCost[i])
            dist[i][(i-1)%n] = min(dist[i][(i-1)%n], previousCost[i])
        # Floyd-Warshall
        for k in range(n):
            dk = dist[k]
            for i in range(n):
                di = dist[i]
                ik = di[k]
                if ik == INF:
                    continue
                for j in range(n):
                    val = ik + dk[j]
                    if val < di[j]:
                        di[j] = val
        total = 0
        for a, b in zip(s, t):
            u = ord(a) - 97
            v = ord(b) - 97
            total += dist[u][v]
        return total

