class Solution:
    def findMinimumTime(self, strength: List[int], K: int) -> int:
        n = len(strength)
        full_mask = (1 << n) - 1
        INF = 10**18
        dp = [INF] * (1 << n)
        dp[0] = 0
        for mask in range(1 << n):
            if dp[mask] == INF:
                continue
            # current factor X
            X = 1 + K * bin(mask).count('1')
            for i in range(n):
                if not (mask >> i) & 1:
                    t = (strength[i] + X - 1) // X
                    new_mask = mask | (1 << i)
                    if dp[new_mask] > dp[mask] + t:
                        dp[new_mask] = dp[mask] + t
        return dp[full_mask]

